B.VJ=new A.m(B.x,"Modal fiiller zorunluluk ve izin ifade eder",'Modal fiiller, **zorunluluk derecelerini** ifade etti\u011fi i\xe7in havac\u0131l\u0131k \u0130ngilizcesinde son derece \xf6nemlidir. "must" ile "should" aras\u0131ndaki fark g\xfcvenlik sonu\xe7lar\u0131 do\u011furabilir.\n\n**must** = zorunlu (yasal gereklilik)\n**should** = \xf6nerilen (en iyi uygulama)\n**may** = izin verilen (serbest)\n**can** = yetenek / teorik olas\u0131l\u0131k',null,null,null)
