B.W1=new A.m(B.x,"Acil durum dili tam olarak \xf6\u011frenilmelidir","Ger\xe7ek acil durumlarda ve s\u0131nav sorular\u0131nda do\u011fru kelimeyi kullanmak kritik fark yaratabilir. ICAO standartlar\u0131 acil durumlar i\xe7in belirli terimler tan\u0131mlar \u2014 bunlar farkl\u0131 ifadeyle anlat\u0131lamaz.\n\nBu ders, acil durumla ilgili s\u0131nav sorular\u0131nda en s\u0131k kar\u015f\u0131la\u015f\u0131lan kelime bilgisine odaklan\u0131r.",null,null,null)
B.Zz=new A.m(B.u,"\ud83d\udea8 Acil Durum S\u0131n\u0131fland\u0131rmas\u0131","**Distress** \u2014 state of being threatened by serious and/or imminent danger, requiring immediate assistance (MAYDAY)\n\n**Urgency** \u2014 condition concerning the safety of an aircraft or other vehicle, or of some person on board or in sight, but not requiring immediate assistance (PAN-PAN)\n\n**Emergency** \u2014 broad term covering both distress and urgency situations\n\n**Incident** \u2014 occurrence other than an accident associated with flight operation\n**Accident** \u2014 occurrence resulting in death, injury, or substantial aircraft damage",null,null,null)
B.VL=new A.m(B.u,"\ud83d\udd25 Acil Durum Eylem Kelime Bilgisi","**Declare** \u2014 formally announce an emergency state\n**Divert** \u2014 change destination to an alternate airport\n**Squawk** \u2014 set transponder code\n**Dump fuel** \u2014 jettison fuel to reduce landing weight (on equipped aircraft)\n**Depressurize** \u2014 controlled or rapid loss of cabin pressure\n**Evacuate** \u2014 rapid exit of passengers and crew\n**Ditch** \u2014 emergency landing on water\n**Abort** \u2014 discontinue a takeoff roll",null,null,null)
B.Qo=new A.a1("The captain declared a MAYDAY due to rapid decompression at FL350.","Kaptan, FL350'de h\u0131zl\u0131 bas\u0131n\xe7 kayb\u0131 nedeniyle MAYDAY ilan etti.","declared a MAYDAY")
B.QV=new A.a1("The crew was forced to divert to Valencia after a hydraulic failure.","Ekip, hidrolik ar\u0131zas\u0131n\u0131n ard\u0131ndan Valencia'ya y\xf6n de\u011fi\u015ftirmek zorunda kald\u0131.","divert")
B.PG=new A.a1("Following the gear malfunction, the captain decided to abort the landing.","\u0130ni\u015f tak\u0131m\u0131 ar\u0131zas\u0131n\u0131n ard\u0131ndan kaptan ini\u015fi iptal etmeye karar verdi.","abort")
