B.aaA=s(["Direct source of good lighting","Inspection aids such as mirrors","Complete disassembly of the aircraft","Surface cleaning"],t.s)
B.akv=new A.r(-71,B.P,602,"Which of the following is NOT necessarily required for a Detailed Inspection?",B.aaA,2,B.q,null,null,null)
