B.uv=new A.aF("reading_5","SID/STAR Prosed\xfcrleri","Kalk\u0131\u015f ve var\u0131\u015f prosed\xfcr belgelerini okuma","reading","\ud83d\uddfa\ufe0f",B.a3Y)
B.a0G=new A.m(B.x,"Kaza raporlar\u0131 karma\u015f\u0131k metinlerdir","Havac\u0131l\u0131k kaza soru\u015fturma raporlar\u0131 (ICAO Ek 13 standartlar\u0131na g\xf6re haz\u0131rlananlar gibi) havac\u0131l\u0131k \u0130ngilizcesi s\u0131navlar\u0131nda s\u0131nanan en karma\u015f\u0131k metinlerdendir.\n\nTeknik terminoloji, edilgen yap\u0131lar, dolayl\u0131 anlat\u0131m ve ko\u015ful \xe7\u0131kar\u0131mlar\u0131n\u0131 tek bir belgede bir araya getirirler.",null,null,null)
B.Vu=new A.m(B.u,"\ud83d\udccb Rapor Yap\u0131s\u0131","Standart bir kaza raporu \u015funlar\u0131 i\xe7erir:\n1. **\xd6zet (Synopsis)** \u2014 kazan\u0131n k\u0131sa \xf6zeti\n2. **Olgusal bilgi** \u2014 u\xe7ak, m\xfcrettebat, hava durumu, havaliman\u0131 verileri\n3. **Analiz** \u2014 ne oldu\u011fu ve neden (neden zinciri)\n4. **Bulgular** \u2014 tespit edilen olgular\n5. **Neden** \u2014 muhtemel neden(ler)\n6. **G\xfcvenlik \xf6nerileri** \u2014 neyin de\u011fi\u015fmesi gerekti\u011fi\n\nS\u0131nav sorular\u0131 genellikle **Olgusal Bilgi** ve **Analiz** b\xf6l\xfcmlerini hedefler.",null,null,null)
B.Yu=new A.m(B.u,"\ud83d\udd0d Kritik Okuma Becerileri","Kaza raporu pasajlar\u0131 i\xe7in:\n\u2022 **S\u0131ralama kelimeleri**: prior to, during, following, subsequently, as a result\n\u2022 **Nedensellik dili**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Bulgu ile \xd6neri** aras\u0131ndaki fark: bulgular olgulard\u0131r; \xf6neriler tavsiyedir\n\u2022 **Contributing factor** \u2260 **Probable cause**: katk\u0131da bulunan fakt\xf6rler durumu a\u011f\u0131rla\u015ft\u0131r\u0131r; muhtemel neden birincil sebeptir",null,null,null)
B.P9=new A.a1("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.Qk=new A.a1("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.a3A=s([B.P9,B.Qk],t.l)
B.a_p=new A.m(B.G,"Rapor Dili \xd6rnekleri",null,B.a3A,null,null)
B.a_v=new A.m(B.aq,"\u2708\ufe0f \u0130leri Okuma Stratejisi","\xdc\xe7 okuma y\xf6ntemi:\n1. **Birinci okuma**: konu ve yap\u0131y\u0131 taramak i\xe7in (30 saniye)\n2. **Soruyu oku**: tam olarak neyin soruldu\u011funu anla\n3. **\u0130kinci okuma**: yaln\u0131zca ilgili paragrafa odaklan\n\nBellekten yan\u0131t verme \u2014 her zaman metinde do\u011frula. \u0130leri d\xfczey sorularda \xe7o\u011funlukla pasajdaki kelimelerin yanl\u0131\u015f ba\u011flamda kullan\u0131ld\u0131\u011f\u0131 **mant\u0131kl\u0131 ama yanl\u0131\u015f** se\xe7enekler bulunur.",null,null,null)
B.a40=s(["To start the engine for the first time","To test the fuel system","To increase engine speed","To test the electrical system"],t.s)
B.anJ=new A.r(-100,B.P,606,"What is the purpose of wet motoring the engine?",B.a40,1,B.p,null,null,null)
B.a2S=s(["Both are turned ON","One is ON and one is OFF","Both are turned OFF","The position does not matter"],t.s)
B.am9=new A.r(-101,B.P,607,"During wet motoring, what is the position of the ignition systems?",B.a2S,2,B.p,null,null,null)
B.a66=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
B.alm=new A.r(-102,B.P,608,"What is monitored during the wet motoring test?",B.a66,2,B.q,null,null,null)
B.a69=s([B.anJ,B.am9,B.alm],t.C)
B.VU=new A.m(B.w,"Pratik Sorular",'"Wet motoring the engine is necessary to test the fuel system. When an engine is wet motored, the two ignition systems are turned OFF and the starter is engaged to turn the HP rotor to 15%-20% N2. At N2 = 15%, the HP fuel shutoff valve control lever is moved to ON and the engine exhaust nozzle is carefully monitored for any sign of fuel."',null,null,B.a69)
B.a9c=s([B.a0G,B.Vu,B.Yu,B.a_p,B.a_v,B.VU],t.q)
B.uZ=new A.aF("reading_2","Kaza Raporu Analizi","\u0130leri okuma anlama","reading","\ud83d\udcd1",B.a9c)
B.Yz=new A.m(B.x,"D\xfc\u015f\xfck g\xf6r\xfc\u015f operasyonlar\u0131 kesin dil gerektirir","CAT II ve CAT III yakla\u015fmalar\u0131 otomatik indi\u015f sistemleri kullan\u0131larak \xe7ok d\xfc\u015f\xfck g\xf6r\xfc\u015f ko\u015fullar\u0131nda ger\xe7ekle\u015ftirilir. Bu prosed\xfcrlerdeki ifadeler, uyar\u0131lar ve s\xf6zl\xfc bildirimler havac\u0131l\u0131k \u0130ngilizcesinin en kesin tan\u0131ml\u0131 ifadeleri aras\u0131ndad\u0131r.\n\nBu alandaki c\xfcmle tamamlama sorular\u0131, prosed\xfcr terminolojisinin tam bilgisini gerektirir.",null,null,null)
B.Y6=new A.m(B.u,"\ud83c\udf2b\ufe0f ILS Kategorileri","**CAT I** \u2014 DH \u2265200ft, RVR \u2265550m (standard ILS)\n**CAT II** \u2014 DH 100\u2013200ft, RVR \u2265300m (needs specific aircraft/crew cert)\n**CAT IIIA** \u2014 DH <100ft OR no DH, RVR \u2265200m\n**CAT IIIB** \u2014 DH <50ft OR no DH, RVR 50\u2013200m\n**CAT IIIC** \u2014 No DH, No RVR limit (still not in service)\n\n**LVP** \u2014 Low Visibility Procedures (activated by airport when RVR <600m)\n**LVT** \u2014 Low Visibility Takeoff",null,null,null)
B.a0S=new A.m(B.u,"\ud83d\udce2 CAT III S\xf6zl\xfc Bildirimleri",'Standart CAT III yakla\u015fma s\xf6zl\xfc bildirimleri (s\u0131rayla):\n1. "**Localizer alive**" \u2014 ILS localizer yakaland\u0131\n2. "**Glide slope alive**" \u2014 dikey rehberlik yakaland\u0131\n3. "**Land 3**" \u2014 otomatik indi\u015f modu onayland\u0131 (A320 ailesi)\n4. "**1,000 feet**" \u2014 standart kontrol irtifas\u0131\n5. "**500 feet**" \u2014 istikrar kontrol\xfc\n6. "**100 feet**" \u2014 g\xf6rsel veya etrafta d\xf6n\xfc\u015f karar\u0131\n7. "**50, 40, 30, 20, 10**" \u2014 radyo altimetre \xe7a\u011fr\u0131lar\u0131\n8. "**Touchdown**" \u2192 "**Decelerate**" \u2192 "**Vacate**"',null,null,null)
B.Pu=new A.a1("During LVP, ground movement must be strictly controlled to prevent runway incursion.","LVP s\u0131ras\u0131nda pist ihlalini \xf6nlemek i\xe7in yer hareketi kesinlikle kontrol edilmelidir.","LVP")
B.OY=new A.a1("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
B.a4O=s([B.Pu,B.OY],t.l)
B.X0=new A.m(B.G,"CAT III Tamamlama \xd6rnekleri",null,B.a4O,null,null)
B.X6=new A.m(B.aq,"\u2708\ufe0f S\u0131nav \u0130pucu",'S\u0131navlar i\xe7in CAT II/III temel ayr\u0131mlar\u0131:\n\u2022 **DH** = Karar \u0130rtifas\u0131 (radyo altimetre tabanl\u0131, CAT II/III)\n\u2022 **DA** = Karar Y\xfcksekli\u011fi (barometre tabanl\u0131, CAT I)\n\u2022 **RVR** = Pist G\xf6r\xfc\u015f Mesafesi (transmissometre ile \xf6l\xe7\xfcl\xfcr)\n\u2022 Otomatik taksi/fren kullan\u0131labilirse CAT IIIB yakla\u015fma **Karar \u0130rtifas\u0131 olmadan** yap\u0131labilir\n\u2022 LVP, d\xfc\u015f\xfck g\xf6r\xfc\u015fl\xfc kalk\u0131\u015flar\u0131 otomatik olarak iptal etmez \u2014 ayr\u0131 LVT minimumlari vard\u0131r\n\u2022 CAT III i\xe7in "zorunlu g\xf6rsel referans" CAT I\'e g\xf6re **daha azd\u0131r** (yaln\u0131zca pist kenar \u0131\u015f\u0131klar\u0131 yeterli olabilir)',null,null,null)
B.a7k=s(["Minimum Descent","Decision Height","Decision Altitude","Obstacle Clearance"],t.s)
B.aj6=new A.r(-280,B.aA,980,"A CAT III approach uses \u2026\u2026\u2026\u2026 altitude as the reference point for the go-around decision.",B.a7k,1,B.q,null,null,null)
B.a65=s(["800 meters","1,000 meters","600 meters","400 meters"],t.s)
B.alp=new A.r(-281,B.aA,981,"LVP (Low Visibility Procedures) are normally activated when RVR drops below \u2026\u2026\u2026\u2026.",B.a65,2,B.aM,null,null,null)
B.a5t=s(["550 meters","300 meters","200 meters","100 meters"],t.s)
