B.Xz=new A.m(B.x,"Neden kaza raporu dili \xf6\u011frenilmeli?","Kaza soru\u015fturma raporlar\u0131 (NTSB, AAIB, DGCA vb.) havac\u0131l\u0131k g\xfcvenli\u011finin temel belgelerindendir. Bu raporlar belirli bir dil kullan\u0131r: bulgular (findings), nedenler (causes), katk\u0131da bulunan fakt\xf6rler (contributing factors) ve g\xfcvenlik \xf6nerileri (safety recommendations).\n\nS\u0131nav sorular\u0131 ve mesleki geli\u015fim a\xe7\u0131s\u0131ndan bu dili anlamak kritiktir.",null,null,null)
B.Wj=new A.m(B.u,"\ud83d\udd0d Kaza Raporu Terminolojisi",'**Temel terimler:**\n\u2022 **Probable cause** \u2192 olas\u0131 neden (NTSB kullan\u0131r)\n\u2022 **Causal factor** \u2192 nedensel fakt\xf6r\n\u2022 **Contributing factor** \u2192 katk\u0131da bulunan fakt\xf6r (do\u011frudan neden de\u011fil)\n\u2022 **Finding** \u2192 bulgu (soru\u015fturman\u0131n tespiti)\n\u2022 **Safety recommendation** \u2192 g\xfcvenlik \xf6nerisi\n\u2022 **Chain of events** \u2192 olaylar zinciri\n\u2022 **Accident sequence** \u2192 kaza s\u0131ras\u0131\n\n**Fiil kal\u0131plar\u0131:**\n\u2022 "\u2026was identified as contributing to\u2026" \u2192 katk\u0131da bulunan fakt\xf6r olarak belirlendi\n\u2022 "\u2026failed to\u2026" \u2192 \u2026 yapmay\u0131 ba\u015faramad\u0131\n\u2022 "\u2026resulted in\u2026" \u2192 \u2026 ile sonu\xe7land\u0131\n\u2022 "\u2026led to\u2026" \u2192 \u2026 yol a\xe7t\u0131\n\u2022 "\u2026was a factor in\u2026" \u2192 \u2026 bir etken oldu\n\u2022 "\u2026in the absence of\u2026" \u2192 \u2026 yoklu\u011funda\n\u2022 "\u2026exacerbated by\u2026" \u2192 \u2026 taraf\u0131ndan a\u011f\u0131rla\u015ft\u0131r\u0131ld\u0131',null,null,null)
B.PD=new A.a1('"The probable cause of the accident was the flight crew\'s failure to maintain adequate airspeed during the approach, resulting in an aerodynamic stall."',"Kazan\u0131n olas\u0131 nedeni, u\xe7u\u015f m\xfcrettebat\u0131n\u0131n yakla\u015fma s\u0131ras\u0131nda yeterli hava h\u0131z\u0131n\u0131 koruyamamas\u0131 ve bunun sonucunda aerodinamik bir stola neden olmas\u0131d\u0131r.","probable cause \u2026 failure to maintain \u2026 resulting in")
B.Pr=new A.a1('"Contributing factors included crew fatigue, inadequate CRM, and the absence of a stabilised approach policy."',"Katk\u0131da bulunan fakt\xf6rler aras\u0131nda m\xfcrettebat yorgunlu\u011fu, yetersiz CRM ve stabilize yakla\u015fma politikas\u0131n\u0131n yoklu\u011fu say\u0131labilir.","Contributing factors included \u2026 absence of")
B.QK=new A.a1('"The investigation identified a chain of events beginning with an undetected fuel leak that ultimately led to dual engine failure."',"Soru\u015fturma, fark edilmemi\u015f bir yak\u0131t s\u0131z\u0131nt\u0131s\u0131yla ba\u015flayan ve nihayetinde \xe7ift motor ar\u0131zas\u0131na yol a\xe7an olaylar zincirini belirledi.","chain of events \u2026 undetected \u2026 ultimately led to")
