B.Ye=new A.m(B.x,"Operations Manual (OM) dili","Havayolu operasyon el kitaplar\u0131 (OM-A: Genel, OM-B: U\xe7u\u015f Operasyonlar\u0131) karma\u015f\u0131k yasal ve teknik dil i\xe7erir. Bu dili anlamak; kurallar\u0131 do\u011fru yorumlamak ve s\u0131navda ba\u015far\u0131l\u0131 olmak i\xe7in \u015fartt\u0131r.",null,null,null)
B.Vv=new A.m(B.u,"Tipik OM C\xfcmle Kal\u0131plar\u0131",'**Zorunluluk ifadeleri:**\n\u2022 "The commander shall ensure that\u2026"\n\u2022 "\u2026must not commence unless\u2026"\n\u2022 "\u2026is required to carry\u2026"\n\n**Ko\u015fullu izinler:**\n\u2022 "\u2026may be carried out provided that\u2026"\n\u2022 "\u2026is permitted when all of the following conditions are met:"\n\u2022 "\u2026subject to the approval of\u2026"\n\n**Sorumluluk ifadeleri:**\n\u2022 "It is the responsibility of the commander to\u2026"\n\u2022 "The operator shall ensure that\u2026"\n\u2022 "The crew is authorised to\u2026"',null,null,null)
