B.XP=new A.m(B.x,"Engine run-up nedir?",'Bak\u0131m sonras\u0131 motorun zemin testine "engine run-up" veya "ground run" denir. Bu test, motorun operasyonel parametrelerini do\u011frulamak ve ka\xe7aklar\u0131 tespit etmek i\xe7in yap\u0131l\u0131r.',null,null,null)
B.Wt=new A.m(B.u,"Run-up Terminolojisi","**Ground run authorization** \u2014 zemin testi i\xe7in gerekli izin belgesi\n**Idle** \u2014 r\xf6lanti (en d\xfc\u015f\xfck g\xfc\xe7 ayar\u0131)\n**Take-off power (TOGA)** \u2014 maksimum kalk\u0131\u015f g\xfcc\xfc\n**EGT** \u2014 Exhaust Gas Temperature (egzoz gaz s\u0131cakl\u0131\u011f\u0131)\n**N1 / N2** \u2014 fan ve kompres\xf6r h\u0131z y\xfczdesi\n**Oil pressure / oil temperature** \u2014 ya\u011f bas\u0131nc\u0131 / s\u0131cakl\u0131\u011f\u0131\n**Surge** \u2014 kompres\xf6r s\xfcrj\xfc (anormal ses + EGT art\u0131\u015f\u0131)\n**Wet start** \u2014 ate\u015fleme olmaks\u0131z\u0131n yak\u0131t s\u0131zd\u0131rmas\u0131\n**Hung start** \u2014 motor ate\u015flenir fakat r\xf6lantiye ula\u015famaz\n**Hot start** \u2014 EGT ba\u015flang\u0131\xe7 limitini a\u015far",null,null,null)
B.a5X=s(["the engine reached idle faster than normal","EGT exceeded the start temperature limit","the engine failed to ignite","oil pressure dropped during startup"],t.s)
